class IsPhoneNumber(DirtyEquals[str]):
    """
    A class that checks if a value is a plausible phone number, optionally restricted to a specific country.
    """

    # (national number pattern, international number pattern (digits after the leading '+'))
    _country_patterns = {
        'US': (re.compile(r'^\d{10}$'), re.compile(r'^1\d{10}$')),
        'GB': (re.compile(r'^0\d{10}$'), re.compile(r'^44\d{10}$')),
    }
    _generic_international_re = re.compile(r'^\d{8,18}$')
    _generic_national_re = re.compile(r'^\d{7,15}$')
    _allowed_chars_re = re.compile(r'^\+?[\d\s\-.()]+$')

    def __init__(self, country: Optional[str] = None):
        """
        Args:
            country: optional ISO 3166-1 alpha-2 country code (e.g. `'US'`, `'GB'`) used to restrict validation
                to that country's phone number formats. If omitted, a generic, pragmatic check is used.

        Countries with dedicated validation rules: `US`, `GB`. For any other country code, a generic
        international format check (`+` followed by a country code and 7-15 digits) is used instead.

        ```py title="IsPhoneNumber"
        from dirty_equals import IsPhoneNumber

        assert '+1-555-123-4567' == IsPhoneNumber
        assert '555-123-4567' == IsPhoneNumber('US')
        assert '+1-555-123-4567' == IsPhoneNumber('US')
        assert '020 7946 0958' == IsPhoneNumber('GB')
        assert '+44 20 7946 0958' == IsPhoneNumber('GB')
        assert '555-123-4567' != IsPhoneNumber('GB')
        assert '020 7946 0958' != IsPhoneNumber('US')
        assert '+33 1 42 68 53 00' == IsPhoneNumber('FR')
        assert 12345 != IsPhoneNumber
        ```
        """
        self.country = country
        super().__init__(country or plain_repr('*'))

    def equals(self, other: Any) -> bool:
        if not isinstance(other, str):
            return False

        if not self._allowed_chars_re.match(other):
            return False

        international = other.strip().startswith('+')
        digits = re.sub(r'\D', '', other)
        if not digits:
            return False

        if self.country is None:
            if international:
                return bool(self._generic_international_re.match(digits))
            return bool(
                any(nat.match(digits) for nat, _ in self._country_patterns.values())
                or self._generic_national_re.match(digits)
            )

        patterns = self._country_patterns.get(self.country)
        if patterns is not None:
            national_re, international_re = patterns
            if international:
                return bool(international_re.match(digits))
            return bool(national_re.match(digits))
        else:
            # unsupported/unknown country code, fall back to a generic international check
            if international:
                return bool(self._generic_international_re.match(digits))
            return False

